const start = readme.indexOf('## 常用指令');
const end = readme.indexOf('---', start + 20);
const section = readme.slice(start, end);
const cmdRe = /\| \`(\/[a-zA-Z_-]+)/g;
let m, cmds = new Set();
while ((m = cmdRe.exec(section))) cmds.push ? null : cmds.add(m[1]);

for (const c of cmds) {
  const esc = c.replace(/[.*+?^\${}()|[\]\\\\]/g, '\\\\\$&');
  const found = html.includes(c);
  console.log(found ? 'OK  ' : 'MISS', c);
}
"
